import React, { Component } from "react";

class MultiplayerModal extends Component {
  constructor(props) {
    super(props);
    this.state = {
      activeTab: "host", // 'host' ou 'join'
      inviteInput: "",
      answerInput: "",
      copiedInvite: false,
      copiedResponse: false,
      closeCountdown: 5
    };
  }

  componentDidUpdate(prevProps) {
    if (this.props.connectionState === "connected" && prevProps.connectionState !== "connected") {
      this.startCloseCountdown();
    }
    if (this.props.connectionState !== "connected" && prevProps.connectionState === "connected") {
      this.clearCloseCountdown();
    }
  }

  componentWillUnmount() {
    this.clearCloseCountdown();
  }

  startCloseCountdown = () => {
    this.setState({ closeCountdown: 5 });
    this.countdownInterval = setInterval(() => {
      const nextCount = this.state.closeCountdown - 1;
      if (nextCount <= 0) {
        this.clearCloseCountdown();
        this.props.toggle(); // Fecha o modal
      } else {
        this.setState({ closeCountdown: nextCount });
      }
    }, 1000);
  };

  clearCloseCountdown = () => {
    if (this.countdownInterval) {
      clearInterval(this.countdownInterval);
      this.countdownInterval = null;
    }
  };

  handleCopy = (text, type) => {
    navigator.clipboard.writeText(text).then(() => {
      if (type === "invite") {
        this.setState({ copiedInvite: true });
        setTimeout(() => this.setState({ copiedInvite: false }), 2000);
      } else if (type === "response") {
        this.setState({ copiedResponse: true });
        setTimeout(() => this.setState({ copiedResponse: false }), 2000);
      }
    });
  };

  render() {
    const {
      isOpen,
      toggle,
      connectionState,
      inviteCode,
      responseCode,
      onCreateSession,
      onJoinSession,
      onAnswerSession,
      onDisconnect,
      onConnectLocalTabs
    } = this.props;

    if (!isOpen) return null;

    const isDisconnected = connectionState === "disconnected";
    const isHostWaiting = connectionState === "generating" || connectionState === "waiting-for-answer";
    const isGuestWaiting = connectionState === "generating-answer";
    const isConnecting = connectionState === "connecting";
    const isConnected = connectionState === "connected";

    return (
      <div className="custom-emulator-modal">
        <div className="custom-emulator-modal-content" style={{ maxWidth: "460px", height: "auto", maxHeight: "90%" }}>
          <div className="custom-emulator-modal-header">
            <h4>Conexão Cooperativa Co-op</h4>
            <button className="custom-emulator-modal-close-btn" onClick={toggle}>
              &times;
            </button>
          </div>

          <div className="custom-emulator-modal-body" style={{ padding: "20px" }}>
            {/* TABS DE SELEÇÃO INICIAL */}
            {isDisconnected && (
              <div className="custom-modal-tabs" style={{ marginBottom: "20px" }}>
                <button
                  className={`custom-modal-tab-button ${this.state.activeTab === "host" ? "active" : ""}`}
                  onClick={() => this.setState({ activeTab: "host" })}
                >
                  <i className="fa fa-server" style={{ marginRight: "6px" }}></i> Criar Sala (Host)
                </button>
                <button
                  className={`custom-modal-tab-button ${this.state.activeTab === "join" ? "active" : ""}`}
                  onClick={() => this.setState({ activeTab: "join" })}
                >
                  <i className="fa fa-plug" style={{ marginRight: "6px" }}></i> Entrar (Convidado)
                </button>
              </div>
            )}

            {/* FLUXO DO HOST */}
            {(this.state.activeTab === "host" || isHostWaiting) && !isGuestWaiting && !isConnecting && !isConnected && (
              <div className="multiplayer-stepper">
                {/* HOST ETAPA 1 */}
                <div className={`step-card ${isDisconnected ? "active" : "disabled"}`}>
                  <div className="step-header">
                    <span className="step-badge">1</span>
                    <span className="step-title">Iniciar Emulação Remota</span>
                  </div>
                  {isDisconnected ? (
                    <div className="step-body">
                      <p>Inicie a sala co-op. Suas trapaças (cheats) e o carregamento da ROM serão espelhados para o convidado automaticamente.</p>
                      <button
                        className="custom-btn custom-btn-primary"
                        onClick={onCreateSession}
                        style={{ width: "100%", marginTop: "8px" }}
                      >
                        Criar Sala Co-op
                      </button>
                    </div>
                  ) : (
                    <div className="step-body">Sala co-op iniciada com sucesso.</div>
                  )}
                </div>

                {/* HOST ETAPA 2 */}
                <div className={`step-card ${connectionState === "waiting-for-answer" ? "active" : "disabled"}`}>
                  <div className="step-header">
                    <span className="step-badge">2</span>
                    <span className="step-title">Enviar Convite ao Parceiro</span>
                  </div>
                  {connectionState === "generating" && (
                    <div className="step-body" style={{ textAlign: "center", padding: "10px 0" }}>
                      <i className="fa fa-refresh fa-spin" style={{ marginRight: "8px", color: "#e52521" }}></i>
                      Gerando código do convite...
                    </div>
                  )}
                  {connectionState === "waiting-for-answer" && (
                    <div className="step-body">
                      <p>Copie e envie o convite criptografado abaixo para o segundo jogador:</p>
                      <div className="code-box-wrapper" style={{ marginTop: "6px" }}>
                        <textarea
                          className="custom-form-input"
                          readOnly
                          value={inviteCode}
                          rows={2}
                          style={{ resize: "none", fontFamily: "monospace", fontSize: "0.75em", background: "#111" }}
                          onClick={(e) => e.target.select()}
                        />
                        <button
                          className="custom-btn custom-btn-sm custom-btn-primary code-box-copy-btn"
                          onClick={() => this.handleCopy(inviteCode, "invite")}
                        >
                          {this.state.copiedInvite ? "Copiado!" : "Copiar"}
                        </button>
                      </div>
                    </div>
                  )}
                </div>

                {/* HOST ETAPA 3 */}
                <div className={`step-card ${connectionState === "waiting-for-answer" ? "active" : "disabled"}`}>
                  <div className="step-header">
                    <span className="step-badge">3</span>
                    <span className="step-title">Cole o Código de Resposta</span>
                  </div>
                  {connectionState === "waiting-for-answer" && (
                    <div className="step-body">
                      <p>Insira a chave de resposta gerada pelo convidado para estabelecer a ponte P2P:</p>
                      <textarea
                        className="custom-form-input"
                        placeholder="Cole o código de resposta Base64 aqui..."
                        value={this.state.answerInput}
                        onChange={(e) => this.setState({ answerInput: e.target.value })}
                        rows={2}
                        style={{ resize: "none", fontFamily: "monospace", fontSize: "0.75em", marginTop: "6px" }}
                      />
                      <button
                        className="custom-btn custom-btn-primary"
                        onClick={() => onAnswerSession(this.state.answerInput)}
                        disabled={!this.state.answerInput.trim()}
                        style={{ width: "100%", marginTop: "10px" }}
                      >
                        Estabelecer Conexão
                      </button>
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* FLUXO DO CONVIDADO */}
            {(this.state.activeTab === "join" || isGuestWaiting) && !isHostWaiting && !isConnecting && !isConnected && (
              <div className="multiplayer-stepper">
                {/* CONVIDADO ETAPA 1 */}
                <div className={`step-card ${isDisconnected ? "active" : "disabled"}`}>
                  <div className="step-header">
                    <span className="step-badge">1</span>
                    <span className="step-title">Inserir Convite do Host</span>
                  </div>
                  {isDisconnected ? (
                    <div className="step-body">
                      <p>Cole a chave de convite fornecida pelo criador da sala:</p>
                      <textarea
                        className="custom-form-input"
                        placeholder="Cole o código Base64 do Host aqui..."
                        value={this.state.inviteInput}
                        onChange={(e) => this.setState({ inviteInput: e.target.value })}
                        rows={2}
                        style={{ resize: "none", fontFamily: "monospace", fontSize: "0.75em", marginTop: "6px" }}
                      />
                      <button
                        className="custom-btn custom-btn-primary"
                        onClick={() => onJoinSession(this.state.inviteInput)}
                        disabled={!this.state.inviteInput.trim()}
                        style={{ width: "100%", marginTop: "10px" }}
                      >
                        Carregar Jogo e Avançar
                      </button>
                    </div>
                  ) : (
                    <div className="step-body">Jogo carregado e convite processado.</div>
                  )}
                </div>

                {/* CONVIDADO ETAPA 2 */}
                <div className={`step-card ${connectionState === "generating-answer" ? "active" : "disabled"}`}>
                  <div className="step-header">
                    <span className="step-badge">2</span>
                    <span className="step-title">Enviar Código de Resposta</span>
                  </div>
                  {connectionState === "generating-answer" && (
                    <div className="step-body">
                      <p>Copie e envie a resposta gerada de volta para o Host no chat/WhatsApp:</p>
                      <div className="code-box-wrapper" style={{ marginTop: "6px" }}>
                        <textarea
                          className="custom-form-input"
                          readOnly
                          value={responseCode}
                          rows={2}
                          style={{ resize: "none", fontFamily: "monospace", fontSize: "0.75em", background: "#111" }}
                          onClick={(e) => e.target.select()}
                        />
                        <button
                          className="custom-btn custom-btn-sm custom-btn-primary code-box-copy-btn"
                          onClick={() => this.handleCopy(responseCode, "response")}
                        >
                          {this.state.copiedResponse ? "Copiado!" : "Copiar"}
                        </button>
                      </div>
                    </div>
                  )}
                </div>

                {/* CONVIDADO ETAPA 3 */}
                <div className={`step-card ${connectionState === "generating-answer" ? "active" : "disabled"}`}>
                  <div className="step-header">
                    <span className="step-badge">3</span>
                    <span className="step-title">Aguardando Início</span>
                  </div>
                  {connectionState === "generating-answer" && (
                    <div className="step-body">
                      <p>Aguardando o Host validar sua resposta para abrir os canais de controle e vídeo...</p>
                      <div className="loading-bar-wrapper" style={{ width: "100%", marginTop: "8px" }}>
                        <div className="loading-bar-progress"></div>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* ESTADO CONECTANDO */}
            {isConnecting && (
              <div className="connection-loading">
                <i className="fa fa-refresh fa-spin" style={{ fontSize: "2.5rem", color: "#e52521" }}></i>
                <div>
                  <h5 style={{ color: "#fff", margin: "0 0 4px 0" }}>Pareando Dispositivos</h5>
                  <p style={{ fontSize: "0.85em", color: "#aaa", margin: 0 }}>Estabelecendo canal P2P direto criptografado...</p>
                </div>
                <div className="loading-bar-wrapper">
                  <div className="loading-bar-progress"></div>
                </div>
              </div>
            )}

            {/* ESTADO CONECTADO */}
            {isConnected && (
              <div className="connection-loading">
                <i className="fa fa-check-circle" style={{ fontSize: "3rem", color: "#28a745" }}></i>
                <div>
                  <h5 style={{ color: "#28a745", margin: "0 0 4px 0" }}>Conectado com Sucesso!</h5>
                  <p style={{ fontSize: "0.85em", color: "#aaa", margin: 0 }}>
                    A emulação está sincronizada. Os inputs estão compartilhados de forma co-op direta.
                  </p>
                </div>
                <button
                  className="custom-btn custom-btn-danger"
                  onClick={onDisconnect}
                  style={{ width: "100%", marginTop: "10px" }}
                >
                  Desconectar Partida
                </button>
              </div>
            )}

            {/* TESTE LOCAL DE ABAS */}
            {isDisconnected && (
              <div className="local-test-card">
                <p style={{ fontSize: "0.8em", color: "#aaa", margin: "0 0 8px 0" }}>
                  <strong>Quer apenas testar?</strong> Use o atalho para parear duas abas locais no mesmo navegador de forma instantânea.
                </p>
                <button
                  className="custom-btn custom-btn-sm custom-btn-outline-primary"
                  onClick={onConnectLocalTabs}
                  style={{ width: "100%" }}
                >
                  Conectar Duas Abas Locais
                </button>
              </div>
            )}
          </div>

          <div className="custom-emulator-modal-footer">
            <button className="custom-btn custom-btn-outline-primary" onClick={toggle}>
              {isConnected ? `Fechar (${this.state.closeCountdown}s)` : "Fechar"}
            </button>
          </div>
        </div>
      </div>
    );
  }
}

export default MultiplayerModal;
