import Raven from "raven-js";
import React, { Component } from "react";
import PropTypes from "prop-types";
import { NES } from "jsnes";
import FrameTimer from "./FrameTimer";
import GamepadController from "./GamepadController";
import KeyboardController from "./KeyboardController";
import Screen from "./Screen";
import Speakers from "./Speakers";
import { decodeGameGenie } from "./CheatManager";

const Mappers = require("jsnes/src/mappers");
const ROM = require("jsnes/src/rom");

// Register Mapper 226
ROM.prototype.getMapperName = function () {
  if (this.mapperType === 226) {
    return "76-in-1 / 42-in-1 Multicart";
  }
  if (this.mapperType >= 0 && this.mapperType < this.mapperName.length) {
    return this.mapperName[this.mapperType];
  }
  return "Unknown Mapper, " + this.mapperType;
};

Mappers[226] = function (nes) {
  this.nes = nes;
};

Mappers[226].prototype = new Mappers[0]();

Mappers[226].prototype.reset = function () {
  Mappers[0].prototype.reset.apply(this);
  this.reg8000 = 0;
  this.reg8001 = 0;
};

Mappers[226].prototype.write = function (address, value) {
  if (address < 0x8000) {
    Mappers[0].prototype.write.apply(this, arguments);
    return;
  }

  if ((address & 1) === 0) {
    this.reg8000 = value;
  } else {
    this.reg8001 = value;
  }

  const val8000 = this.reg8000;
  const val8001 = this.reg8001;

  const mirroring = (val8000 >> 6) & 1;
  const prgMode = (val8000 >> 5) & 1;
  const pLow = (val8000 & 0x1f) | (((val8000 >> 7) & 1) << 5);
  const pHigh = val8001 & 1;

  const reg = (pHigh << 6) | pLow;

  if (mirroring === 0) {
    this.nes.ppu.setMirroring(this.nes.rom.HORIZONTAL_MIRRORING);
  } else {
    this.nes.ppu.setMirroring(this.nes.rom.VERTICAL_MIRRORING);
  }

  if (prgMode === 0) {
    const bank = reg & 0x7e;
    this.loadRomBank(bank, 0x8000);
    this.loadRomBank(bank | 1, 0xc000);
  } else {
    this.loadRomBank(reg, 0x8000);
    this.loadRomBank(reg, 0xc000);
  }
};

Mappers[226].prototype.loadROM = function () {
  if (!this.nes.rom.valid) {
    throw new Error("Mapper 226: Invalid ROM! Unable to load.");
  }

  this.loadRomBank(0, 0x8000);
  this.loadRomBank(1, 0xc000);

  this.loadCHRROM();

  this.nes.cpu.requestIrq(this.nes.cpu.IRQ_RESET);
};

/*
 * Runs the emulator.
 *
 * The only UI is a canvas element. It assumes it is a singleton in various ways
 * (binds to window, keyboard, speakers, etc).
 */
class Emulator extends Component {
  render() {

    return (
      <Screen
        aspectRatio={this.props.aspectRatio}
        ref={screen => {
          this.screen = screen;
        }}
        onGenerateFrame={() => {
          if (this.nes) this.nes.frame();
        }}
        onMouseDown={(x, y) => {
          if (this.nes) {
            this.nes.zapperMove(x, y);
            this.nes.zapperFireDown();
          }
        }}
        onMouseUp={() => {
          if (this.nes) this.nes.zapperFireUp();
        }}
      />
    );
  }

  componentDidMount() {
    const isGuestStreaming = !this.props.isHost && this.props.hasPeerConnected;

    if (!isGuestStreaming) {
      requestAnimationFrame(() => {
        this.fitInParent();
      });

      this.speakers = new Speakers({
        onBufferUnderrun: (actualSize, desiredSize) => {
          if (this.props.paused) {
            return;
          }

          this.frameTimer.generateFrame();
          if (this.speakers.buffer.size() < desiredSize) {
            this.frameTimer.generateFrame();
          }
        }
      });

      this.nes = new NES({
        onFrame: this.screen.setBuffer,
        onStatusUpdate: () => {},
        onAudioSample: this.speakers.writeSample,
        sampleRate: this.speakers.getSampleRate()
      });

      const originalLoadROM = this.nes.loadROM.bind(this.nes);
      this.nes.loadROM = (romData) => {
        originalLoadROM(romData);
        if (this.nes.mmap) {
          const originalLoad = this.nes.mmap.load.bind(this.nes.mmap);
          this.nes.mmap.load = (address) => {
            address &= 0xffff;
            if (address >= 0x8000 && this.activeCheatsList) {
              for (let i = 0; i < this.activeCheatsList.length; i++) {
                const cheat = this.activeCheatsList[i];
                if (cheat.enabled && cheat.address === address) {
                  const originalValue = originalLoad(address);
                  if (cheat.compare === null || originalValue === cheat.compare) {
                    return cheat.value;
                  }
                }
              }
            }
            return originalLoad(address);
          };
        }
        this.updateActiveCheats(this.props.activeCheats);
      };

      window["nes"] = this.nes;
    }

    this.localButtons = [false, false, false, false, false, false, false, false];
    this.localFrameIndex = 0;
    this.localInputBuffer = {};
    this.remoteInputBuffer = {};

    this.getButtonByte = () => {
      let byte = 0;
      for (let b = 0; b < 8; b++) {
        if (this.localButtons[b]) {
          byte |= (1 << b);
        }
      }
      return byte;
    };

    this.sendGuestInput = () => {
      const byte = this.getButtonByte();
      if (this.props.isLocalChannelMode) {
        this.props.sendLocalChannelData(`i,${byte}`);
      } else if (this.props.peer) {
        try {
          this.props.peer.send(`i,${byte}`);
        } catch (e) {
          console.error("Failed to send guest inputs:", e);
        }
      }
    };

    this.handleLocalButtonDown = (playerId, buttonId) => {
      const isStreaming = !this.props.isHost && this.props.hasPeerConnected;
      if (isStreaming) {
        this.localButtons[buttonId] = true;
        this.sendGuestInput();
      } else {
        const isMulti = !!((this.props.peer && this.props.hasPeerConnected) || this.props.isLocalChannelMode);
        const activePlayer = isMulti ? 1 : playerId;
        if (this.nes) {
          this.nes.buttonDown(activePlayer, buttonId);
        }
      }
    };

    this.handleLocalButtonUp = (playerId, buttonId) => {
      const isStreaming = !this.props.isHost && this.props.hasPeerConnected;
      if (isStreaming) {
        this.localButtons[buttonId] = false;
        this.sendGuestInput();
      } else {
        const isMulti = !!((this.props.peer && this.props.hasPeerConnected) || this.props.isLocalChannelMode);
        const activePlayer = isMulti ? 1 : playerId;
        if (this.nes) {
          this.nes.buttonUp(activePlayer, buttonId);
        }
      }
    };

    if (!isGuestStreaming) {
      this.frameTimer = new FrameTimer({
        onGenerateFrame: () => this.executeFrame(true),
        onWriteFrame: Raven.wrap(this.handleWriteFrame),
        isMultiplayer: () => false
      });
    }

    // Set up gamepad and keyboard
    this.gamepadController = new GamepadController({
      onButtonDown: this.handleLocalButtonDown,
      onButtonUp: this.handleLocalButtonUp
    });

    this.gamepadController.loadGamepadConfig();
    this.gamepadPolling = this.gamepadController.startPolling();

    this.keyboardController = new KeyboardController({
      onButtonDown: this.gamepadController.disableIfGamepadEnabled(
        this.handleLocalButtonDown
      ),
      onButtonUp: this.gamepadController.disableIfGamepadEnabled(
        this.handleLocalButtonUp
      )
    });

    this.keyboardController.loadKeys();

    document.addEventListener("keydown", this.keyboardController.handleKeyDown);
    document.addEventListener("keyup", this.keyboardController.handleKeyUp);
    document.addEventListener(
      "keypress",
      this.keyboardController.handleKeyPress
    );

    if (!isGuestStreaming) {
      this.nes.loadROM(this.props.romData);
      this.start();

      if (this.props.isHost && this.speakers) {
        this.speakers.onAudioDataCallback = (left, right) => {
          if (this.props.isLocalChannelMode) {
            if (this.props.sendLocalAudioData) {
              this.props.sendLocalAudioData(left, right);
            }
          } else if (this.props.peer && this.props.hasPeerConnected) {
            try {
              const audioPacket = new Float32Array(left.length + right.length);
              audioPacket.set(left, 0);
              audioPacket.set(right, left.length);
              this.props.peer.send(audioPacket);
            } catch (e) {}
          }
        };
      }
    } else {
      this.speakers = new Speakers({
        onBufferUnderrun: null
      });
      this.speakers.start();
    }
    
    if (this.props.onMount) {
      this.props.onMount();
    }
  }

  componentWillUnmount() {
    const isGuestStreaming = !this.props.isHost && this.props.hasPeerConnected;
    if (!isGuestStreaming) {
      this.stop();
    }

    // Unbind keyboard
    document.removeEventListener(
      "keydown",
      this.keyboardController.handleKeyDown
    );
    document.removeEventListener("keyup", this.keyboardController.handleKeyUp);
    document.removeEventListener(
      "keypress",
      this.keyboardController.handleKeyPress
    );

    // Stop gamepad
    this.gamepadPolling.stop();

    window["nes"] = undefined;
  }

  componentDidUpdate(prevProps) {
    const isGuestStreaming = !this.props.isHost && this.props.hasPeerConnected;
    const wasGuestStreaming = !prevProps.isHost && prevProps.hasPeerConnected;

    if (isGuestStreaming && !wasGuestStreaming) {
      this.stop();
      this.frameTimer = null;
      this.nes = null;
      window["nes"] = undefined;

      if (this.speakers) {
        this.speakers.stop();
      }
      this.speakers = new Speakers({
        onBufferUnderrun: null
      });
      this.speakers.start();
      
      requestAnimationFrame(() => {
        this.fitInParent();
      });
      return;
    }

    if (isGuestStreaming) {
      if (this.props.aspectRatio !== prevProps.aspectRatio) {
        this.fitInParent();
      }
      return;
    }

    if (this.props.paused !== prevProps.paused) {
      if (this.props.paused) {
        this.stop();
      } else {
        this.start();
      }
    }

    if (this.props.activeCheats !== prevProps.activeCheats) {
      this.updateActiveCheats(this.props.activeCheats || []);
    }

    if (this.props.aspectRatio !== prevProps.aspectRatio) {
      this.fitInParent();
    }

    // TODO: handle changing romData
  }

  updateActiveCheats = (cheats) => {
    this.activeCheatsList = (cheats || []).map(cheat => {
      const decoded = decodeGameGenie(cheat.code);
      return {
        enabled: cheat.enabled,
        address: decoded ? decoded.address : null,
        value: decoded ? decoded.value : null,
        compare: decoded ? decoded.compare : null
      };
    });
  };

  start = () => {
    if (this.frameTimer) this.frameTimer.start();
    if (this.speakers) this.speakers.start();
    if (this.nes) {
      this.fpsInterval = setInterval(() => {
        console.log(`FPS: ${this.nes.getFPS()}`);
      }, 1000);
    }
  };

  stop = () => {
    if (this.frameTimer) this.frameTimer.stop();
    if (this.speakers) this.speakers.stop();
    if (this.fpsInterval) {
      clearInterval(this.fpsInterval);
      this.fpsInterval = null;
    }
  };

  reset = () => {
    const isGuestStreaming = !this.props.isHost && this.props.hasPeerConnected;
    if (isGuestStreaming) return;

    this.stop();
    this.nes.loadROM(this.props.romData);
    if (!this.props.paused) {
      this.start();
    }

    if (this.props.isLocalChannelMode) {
      if (this.props.isHost) {
        this.props.sendLocalChannelData("g,r");
      }
    } else if (this.props.peer && this.props.hasPeerConnected && this.props.isHost) {
      try {
        this.props.peer.send("g,r");
      } catch (e) {}
    }
  };

  executeFrame = (fromTimer = false) => {
    if (this.nes) {
      this.nes.frame();
    }
    return true;
  };

  handleStartGame = () => {
    this.localButtons = [false, false, false, false, false, false, false, false];
    const isGuestStreaming = !this.props.isHost && this.props.hasPeerConnected;
    if (!isGuestStreaming) {
      this.reset();
    }
  };

  handleRemoteData = (str) => {
    if (str.startsWith("i,")) {
      const parts = str.split(",");
      const byte = parseInt(parts[1], 10);

      // Injeta os botões recebidos do Convidado diretamente no Player 2 do emulador do Host
      if (this.nes) {
        for (let b = 0; b < 8; b++) {
          if ((byte & (1 << b)) !== 0) {
            this.nes.buttonDown(2, b);
          } else {
            this.nes.buttonUp(2, b);
          }
        }
      }
    } else if (str === "g,s") {
      this.handleStartGame();
    } else if (str === "g,r") {
      this.reset();
    }
  };

  handleWriteFrame = () => {
    if (this.screen) {
      this.screen.writeBuffer();

      const isConnected = this.props.hasPeerConnected;
      if (isConnected) {
        if (this.props.isLocalChannelMode) {
          if (this.props.sendLocalVideoData && this.screen.canvas) {
            const pngData = this.screen.canvas.toDataURL("image/png");
            this.props.sendLocalVideoData(pngData);
          }
        } else if (this.props.peer) {
          try {
            if (this.screen.canvas) {
              const pngData = this.screen.canvas.toDataURL("image/png");
              this.props.peer.send("v," + pngData);
            }
          } catch (e) {}
        }
      }
    }
  };

  handleGuestVideoFrame = (jpegData) => {
    if (this.screen && this.screen.canvas) {
      if (!this.guestImage) {
        this.guestImage = new Image();
        this.guestImage.onload = () => {
          const ctx = this.screen.canvas.getContext("2d");
          if (ctx) {
            ctx.drawImage(this.guestImage, 0, 0);
          }
        };
      }
      this.guestImage.src = jpegData;
    }
  };



  handleGuestAudioSamples = (left, right) => {
    if (this.speakers) {
      this.speakers.writeSamples(left, right);
    }
  };

  initLocalSingleplayer = () => {
    requestAnimationFrame(() => {
      this.fitInParent();
    });

    this.speakers = new Speakers({
      onBufferUnderrun: (actualSize, desiredSize) => {
        if (this.props.paused) {
          return;
        }
        this.frameTimer.generateFrame();
        if (this.speakers.buffer.size() < desiredSize) {
          this.frameTimer.generateFrame();
        }
      }
    });

    this.nes = new NES({
      onFrame: this.screen.setBuffer,
      onStatusUpdate: () => {},
      onAudioSample: this.speakers.writeSample,
      sampleRate: this.speakers.getSampleRate()
    });

    const originalLoadROM = this.nes.loadROM.bind(this.nes);
    this.nes.loadROM = (romData) => {
      originalLoadROM(romData);
      if (this.nes.mmap) {
        const originalLoad = this.nes.mmap.load.bind(this.nes.mmap);
        this.nes.mmap.load = (address) => {
          address &= 0xffff;
          if (address >= 0x8000 && this.activeCheatsList) {
            for (let i = 0; i < this.activeCheatsList.length; i++) {
              const cheat = this.activeCheatsList[i];
              if (cheat.enabled && cheat.address === address) {
                const originalValue = originalLoad(address);
                if (cheat.compare === null || originalValue === cheat.compare) {
                  return cheat.value;
                }
              }
            }
          }
          return originalLoad(address);
        };
      }
      this.updateActiveCheats(this.props.activeCheats);
    };

    window["nes"] = this.nes;

    this.frameTimer = new FrameTimer({
      onGenerateFrame: () => this.executeFrame(true),
      onWriteFrame: Raven.wrap(this.handleWriteFrame),
      isMultiplayer: () => false
    });

    this.nes.loadROM(this.props.romData);
    this.start();
  };

  fitInParent() {
    if (this.screen) {
      this.screen.fitInParent();
    }
  }
}

Emulator.propTypes = {
  paused: PropTypes.bool,
  romData: PropTypes.string.isRequired,
  activeCheats: PropTypes.array,
  aspectRatio: PropTypes.string,
  peer: PropTypes.object,
  isHost: PropTypes.bool,
  hasPeerConnected: PropTypes.bool,
  isLocalChannelMode: PropTypes.bool,
  sendLocalChannelData: PropTypes.func,
  sendLocalAudioData: PropTypes.func,
  onMount: PropTypes.func,
  peerStream: PropTypes.object
};

export default Emulator;
