import React, { Component } from "react";

class CheatsModal extends Component {
  constructor(props) {
    super(props);
    this.state = {
      activeTab: "list",
      searchTerm: ""
    };
  }

  render() {
    const {
      isOpen,
      toggle,
      cheatsList,
      handleToggleCheat,
      handleRemoveCheat,
      handleAddCheat,
      newCheatName,
      newCheatCode,
      setNewCheatName,
      setNewCheatCode
    } = this.props;

    if (!isOpen) return null;

    // Filtra a lista de trapaças baseada no termo de busca digitado pelo usuário (case-insensitive)
    const filteredCheats = cheatsList.filter(cheat =>
      cheat.name.toLowerCase().includes(this.state.searchTerm.toLowerCase())
    );

    return (
      <div className="custom-emulator-modal">
        <div className="custom-emulator-modal-content">
          <div className="custom-emulator-modal-header">
            <h4>Gerenciador de Trapaças</h4>
            <button className="custom-emulator-modal-close-btn" onClick={toggle}>
              &times;
            </button>
          </div>

          <div className="custom-modal-tabs">
            <button
              className={`custom-modal-tab-button ${this.state.activeTab === "list" ? "active" : ""}`}
              onClick={() => this.setState({ activeTab: "list", searchTerm: "" })}
            >
              Trapaças Disponíveis
            </button>
            <button
              className={`custom-modal-tab-button ${this.state.activeTab === "add" ? "active" : ""}`}
              onClick={() => this.setState({ activeTab: "add" })}
            >
              Adicionar Trapaça
            </button>
          </div>

          {this.state.activeTab === "list" && (
            <div className="custom-emulator-modal-body">
              <h5>Trapaças Disponíveis</h5>
              <input
                type="text"
                className="custom-search-input"
                placeholder="🔍 Buscar trapaça por título..."
                value={this.state.searchTerm}
                onChange={e => this.setState({ searchTerm: e.target.value })}
              />

              {cheatsList.length === 0 ? (
                <p style={{ color: "#aaa", margin: "10px 0" }}>Nenhuma trapaça cadastrada para este jogo.</p>
              ) : filteredCheats.length === 0 ? (
                <p style={{ color: "#aaa", margin: "10px 0" }}>Nenhuma trapaça encontrada com o termo "{this.state.searchTerm}".</p>
              ) : (
                <div style={{ flexGrow: 1, overflowY: "auto" }}>
                  {filteredCheats.map((cheat, index) => {
                    // Encontra o index original na cheatsList original para garantir que as funções de alteração funcionem no item correto
                    const originalIndex = cheatsList.indexOf(cheat);
                    return (
                      <div key={index} className="cheat-list-item">
                        <div>
                          <strong>{cheat.name}</strong> 
                          <span className="cheat-code-span">{cheat.code}</span>
                        </div>
                        <div>
                          <button
                            className={`custom-btn custom-btn-sm ${cheat.enabled ? 'custom-btn-primary' : 'custom-btn-outline-primary'}`}
                            onClick={() => handleToggleCheat(originalIndex)}
                            style={{ marginRight: "5px" }}
                          >
                            {cheat.enabled ? "Ativado" : "Desativado"}
                          </button>
                          {cheat.custom && (
                            <button
                              className="custom-btn custom-btn-sm custom-btn-danger"
                              onClick={() => handleRemoveCheat(originalIndex)}
                            >
                              Remover
                            </button>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          )}

          {this.state.activeTab === "add" && (
            <div className="custom-emulator-modal-body">
              <h5>Adicionar Trapaça (Game Genie)</h5>
              <form onSubmit={(e) => {
                handleAddCheat(e);
                this.setState({ activeTab: "list", searchTerm: "" });
              }}>
                <div className="custom-form-group">
                  <label htmlFor="cheatName">Nome da Trapaça</label>
                  <input
                    type="text"
                    id="cheatName"
                    className="custom-form-input"
                    placeholder="Ex: Vidas Infinitas"
                    value={newCheatName}
                    onChange={e => setNewCheatName(e.target.value)}
                    required
                  />
                </div>
                <div className="custom-form-group">
                  <label htmlFor="cheatCode">Código Game Genie</label>
                  <input
                    type="text"
                    id="cheatCode"
                    className="custom-form-input"
                    placeholder="Ex: SLAIYG"
                    value={newCheatCode}
                    onChange={e => setNewCheatCode(e.target.value)}
                    required
                  />
                </div>
                <button className="custom-btn custom-btn-primary" type="submit" style={{ width: "100%", marginTop: "10px" }}>
                  Adicionar Código
                </button>
              </form>
            </div>
          )}

          <div className="custom-emulator-modal-footer">
            <button className="custom-btn custom-btn-outline-primary" onClick={toggle}>
              Fechar
            </button>
          </div>
        </div>
      </div>
    );
  }
}

export default CheatsModal;
